External knowledge:
- "young adults" refers to people in the 20-24 years age group;
- "proficient" corresponds to an Advanced proficiency level.

sql:
SELECT language
FROM in_demand_languages
WHERE reason = 'Easy to learn and use';

SELECT respondent_id
FROM freelancing_experience
WHERE years_of_experience IN ('5-7 years', '8-10 years', '11-15 years', '16-20 years', '21+ years');

SELECT AVG(pl.years_of_experience) AS avg_years_of_experience
FROM programming_languages pl
WHERE pl.language = 'VC++';

SELECT name
FROM respondents
ORDER BY name;

SELECT COUNT(*) AS satisfied_respondents
FROM job_satisfaction
WHERE satisfaction_level = 'Satisfied';

SELECT COUNT(respondent_id) AS demand_count
FROM in_demand_languages
WHERE language = 'Ruby';

